def main():
    ensure_deps()
    from weasyprint import HTML

    html = HTML_CONTENT.replace('{IMG6}', IMG6)

    out_path = os.path.join(DIR, 'panda_onepager.pdf')
    print('1ページPDF生成中...')
    HTML(string=html).write_pdf(out_path)
    print(f'完了: {out_path}')
    return out_path

if __name__ == '__main__':
    main()
